<?php require_once dirname(__DIR__,2).'/app/config/app.php'; require_once ROOT_PATH.'/app/core/db.php'; require_once ROOT_PATH.'/app/core/auth.php'; require_once ROOT_PATH.'/app/core/helpers.php'; session_start_secure(); require_login(); $id=(int)($_GET['id']??0); $status=$_GET['status']??''; $token=$_GET['csrf_token']??''; if(!isset($_SESSION['csrf_token'])||!hash_equals($_SESSION['csrf_token'],$token)){redirect('index.php');} if($id&&in_array($status,['read','archived'])){db()->prepare("UPDATE contact_messages SET status=:s WHERE id=:id")->execute(['s'=>$status,'id'=>$id]);} redirect('index.php');